// Comprehensive CAPS-aligned question bank for all grades

export type QuestionType = 
  | 'free-text' 
  | 'multiple-choice' 
  | 'picture-multiple-choice' 
  | 'fill-in-blank' 
  | 'matching' 
  | 'true-false' 
  | 'drag-drop';

export interface MultipleChoiceOption {
  label: string;
  value: string;
  correct: boolean;
}

export interface Question {
  id: string;
  question: string;
  topic: string;
  answer?: string; // The "correct" answer for the AI to reference
  type?: QuestionType; // Default is 'free-text'
  options?: MultipleChoiceOption[]; // For multiple choice questions
  imageUrl?: string; // URL or SVG string for diagrams/images
  literature?: {
    work: string; // The name of the novel, drama, or poem (e.g., "The Crucible by Arthur Miller")
    type: 'novel' | 'drama' | 'poem'; // Type of literature work
  };
}

