  // =================================
  // Natural Sciences and Technology (Grades 4-6)
  // =================================
  "Natural Sciences and Technology": [
    // --- Grade 4 Questions ---
    { id: 'nst-g4-1', topic: 'Term 1: Living & non-living things, structures: natural & man-made, food chains', question: 'What makes something living?', answer: 'It grows, moves, breathes, needs food, reproduces, responds to changes' },
    { id: 'nst-g4-2', topic: 'Term 1: Living & non-living things, structures: natural & man-made, food chains', question: 'Name a natural structure and a man-made structure.', answer: 'Natural: bird nest, beehive, spider web. Man-made: house, bridge, building' },
    { id: 'nst-g4-3', topic: 'Term 1: Living & non-living things, structures: natural & man-made, food chains', question: 'What is a food chain?', answer: 'Shows who eats who in nature, starting with plants and ending with top predators' },
    { id: 'nst-g4-4', topic: 'Term 2: Materials (properties, uses), energy & movement, process skills (investigation basics)', question: 'What are three properties of materials?', answer: 'Hard/soft, heavy/light, rough/smooth, flexible/rigid, transparent/opaque' },
    { id: 'nst-g4-5', topic: 'Term 2: Materials (properties, uses), energy & movement, process skills (investigation basics)', question: 'What makes things move?', answer: 'Energy or force from pushing or pulling' },
    { id: 'nst-g4-6', topic: 'Term 2: Materials (properties, uses), energy & movement, process skills (investigation basics)', question: 'What are the steps of a scientific investigation?', answer: 'Ask a question, make predictions, plan an experiment, do it, observe results, draw conclusions' },
    { id: 'nst-g4-7', topic: 'Term 3: Solar system basics, planet Earth, soil & rocks', question: 'How many planets are in our solar system?', answer: '8 planets (Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune)' },
    { id: 'nst-g4-8', topic: 'Term 3: Solar system basics, planet Earth, soil & rocks', question: 'What are the three main types of rocks?', answer: 'Igneous, sedimentary, metamorphic' },
    { id: 'nst-g4-9', topic: 'Term 3: Solar system basics, planet Earth, soil & rocks', question: 'What is soil made of?', answer: 'Sand, silt, clay, water, air, and organic matter (dead plants and animals)' },
    { id: 'nst-g4-10', topic: 'Term 4: Energy transfer, life & living, recycling', question: 'How is energy transferred from one thing to another?', answer: 'Through heat, light, sound, electricity, or motion' },
    { id: 'nst-g4-11', topic: 'Term 4: Energy transfer, life & living, recycling', question: 'Why is recycling important?', answer: 'It saves resources, reduces waste, protects the environment, and saves energy' },

    // --- Grade 5 Questions ---
    { id: 'nst-g5-1', topic: 'Term 1: Life & living, interdependence, skeletons & movement', question: 'What do all living things depend on?', answer: 'Each other and the environment for survival' },
    { id: 'nst-g5-2', topic: 'Term 1: Life & living, interdependence, skeletons & movement', question: 'What are the three types of skeletons?', answer: 'Endoskeleton (inside, like humans), exoskeleton (outside, like insects), hydrostatic skeleton (water-filled, like worms)' },
    { id: 'nst-g5-3', topic: 'Term 1: Life & living, interdependence, skeletons & movement', question: 'How does your skeleton help you?', answer: 'Supports your body, protects organs, helps you move, makes blood cells' },
    { id: 'nst-g5-4', topic: 'Term 2: Properties of materials, solutions & mixtures, processes (filtering, sieving)', question: 'What is the difference between a solution and a mixture?', answer: 'Solution: one substance dissolves in another (salt in water). Mixture: substances mixed but not dissolved (sand and water)' },
    { id: 'nst-g5-5', topic: 'Term 2: Properties of materials, solutions & mixtures, processes (filtering, sieving)', question: 'How do you separate sand and water?', answer: 'Filtering - pour through filter paper' },
    { id: 'nst-g5-6', topic: 'Term 2: Properties of materials, solutions & mixtures, processes (filtering, sieving)', question: 'What is sieving used for?', answer: 'Separating solids of different sizes' },
    { id: 'nst-g5-7', topic: 'Term 3: Planet Earth - sedimentary, igneous, metamorphic rocks', question: 'How are sedimentary rocks formed?', answer: 'From layers of sediment (small pieces) pressed together over time' },
    { id: 'nst-g5-8', topic: 'Term 3: Planet Earth - sedimentary, igneous, metamorphic rocks', question: 'How are igneous rocks formed?', answer: 'From cooled and hardened lava or magma' },
    { id: 'nst-g5-9', topic: 'Term 3: Planet Earth - sedimentary, igneous, metamorphic rocks', question: 'How are metamorphic rocks formed?', answer: 'From other rocks changed by heat and pressure deep underground' },
    { id: 'nst-g5-10', topic: 'Term 4: Energy & electricity, electric circuits, technology: simple machines (gears, levers, pulleys)', question: 'What makes a complete electrical circuit?', answer: 'A power source (battery), wires, and something that uses electricity (bulb, motor)' },
    { id: 'nst-g5-11', topic: 'Term 4: Energy & electricity, electric circuits, technology: simple machines (gears, levers, pulleys)', question: 'What is a lever? Give an example.', answer: 'A simple machine that helps lift heavy things. Examples: seesaw, scissors, bottle opener' },
    { id: 'nst-g5-12', topic: 'Term 4: Energy & electricity, electric circuits, technology: simple machines (gears, levers, pulleys)', question: 'What does a pulley do?', answer: 'Helps lift heavy objects by changing the direction of force' },

    // --- Grade 6 Questions ---
    { id: 'nst-g6-1', topic: 'Term 1: Life & living - ecosystems, food webs, biodiversity', question: 'What is an ecosystem?', answer: 'A community of living things and their environment working together' },
    { id: 'nst-g6-2', topic: 'Term 1: Life & living - ecosystems, food webs, biodiversity', question: 'What is the difference between a food chain and a food web?', answer: 'Food chain: one path of who eats who. Food web: many connected food chains' },
    { id: 'nst-g6-3', topic: 'Term 1: Life & living - ecosystems, food webs, biodiversity', question: 'What is biodiversity?', answer: 'The variety of different living things (plants and animals) in an area' },
    { id: 'nst-g6-4', topic: 'Term 2: Materials & matter, reversible & irreversible changes, chemistry basics', question: 'What is a reversible change?', answer: 'Can be undone or changed back. Example: ice melting, water freezing' },
    { id: 'nst-g6-5', topic: 'Term 2: Materials & matter, reversible & irreversible changes, chemistry basics', question: 'What is an irreversible change?', answer: 'Cannot be undone. Example: burning wood, baking bread' },
    { id: 'nst-g6-6', topic: 'Term 3: Planet Earth & beyond - the moon, tides, space exploration', question: 'What causes the tides?', answer: 'The gravitational pull of the moon and sun on Earth\'s oceans' },
    { id: 'nst-g6-7', topic: 'Term 3: Planet Earth & beyond - the moon, tides, space exploration', question: 'What is the first artificial satellite sent to space?', answer: 'Sputnik 1 (launched by the Soviet Union in 1957)' },
    { id: 'nst-g6-8', topic: 'Term 4: Energy & electricity, electric circuits, technology: structures & design (bridges, frames, loads)', question: 'What makes a bridge strong?', answer: 'Good design, strong materials, proper support structure' },
    { id: 'nst-g6-9', topic: 'Term 4: Energy & electricity, electric circuits, technology: structures & design (bridges, frames, loads)', question: 'What is a load?', answer: 'The weight or force that a structure must carry or support' },
  ],

